  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${subject}</title></head><body style="margin:0;padding:0;background-color:#f5f5f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;"><span style="display:none;max-height:0;overflow:hidden;">${previewText || ''}</span><table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f5f0;"><tr><td align="center" style="padding:20px;"><table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);"><tr><td style="background:#2D5A27;padding:20px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:20px;font-weight:bold;">TotalGuard Yard Care</td><td align="right" style="color:#ffffff;font-size:14px;"><a href="tel:6085356057" style="color:#ffffff;text-decoration:none;">(608) 535-6057</a></td></tr><tr><td colspan="2" style="color:#C5A55A;font-size:12px;padding-top:4px;">Madison's Most Trusted Yard Care</td></tr></table></td></tr><tr><td style="padding:30px 30px 10px;"><h1 style="margin:0;color:#2D5A27;font-size:24px;">${headline}</h1></td></tr><tr><td style="padding:10px 30px 20px;color:#1a1a1a;font-size:15px;line-height:1.6;">${bodyHtml}</td></tr>${reviewText ? `<tr><td style="padding:0 30px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#f5f5f0;border-left:4px solid #2D5A27;padding:16px 20px;border-radius:0 6px 6px 0;"><div style="color:#C5A55A;font-size:18px;margin-bottom:8px;">★★★★★</div><div style="color:#333;font-style:italic;font-size:14px;margin-bottom:8px;">"${reviewText}"</div><div style="color:#2D5A27;font-weight:bold;font-size:13px;">— ${reviewerName}</div><div style="color:#888;font-size:11px;">Verified Google Review</div></td></tr></table></td></tr>` : ''}${urgencyText ? `<tr><td style="padding:0 30px 20px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#f0f8f0;border:2px solid #2D5A27;border-radius:8px;padding:16px 20px;text-align:center;"><div style="color:#2D5A27;font-weight:bold;font-size:14px;">${urgencyText}</div></td></tr></table></td></tr>` : ''}<tr><td style="padding:0 30px 20px;" align="center"><table cellpadding="0" cellspacing="0"><tr><td style="background:#2D5A27;border-radius:6px;padding:14px 32px;"><a href="${ctaUrl}" style="color:#ffffff;text-decoration:none;font-weight:bold;font-size:16px;display:inline-block;">${ctaText}</a></td></tr></table></td></tr><tr><td style="padding:0 30px 20px;text-align:center;"><div style="color:#555;font-size:13px;">Prefer to talk? <a href="tel:6085356057" style="color:#2D5A27;font-weight:bold;">(608) 535-6057</a></div></td></tr><tr><td style="padding:10px 30px;text-align:center;border-top:1px solid #eee;"><div style="color:#888;font-size:11px;">✓ Licensed & Insured &nbsp; ✓ 4.9★ Google Rating &nbsp; ✓ 500+ Properties &nbsp; ✓ Satisfaction Guaranteed</div></td></tr><tr><td style="background:#1a1a1a;padding:24px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:14px;font-weight:bold;">TotalGuard Yard Care</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:6px;">7610 Welton Dr, Madison, WI 53711</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:4px;"><a href="tel:6085356057" style="color:#C5A55A;">(608) 535-6057</a> | <a href="mailto:totalguardllc@gmail.com" style="color:#C5A55A;">totalguardllc@gmail.com</a></td></tr><tr><td style="padding-top:10px;"><a href="https://facebook.com/totalguardyardcare" style="color:#C5A55A;font-size:12px;text-decoration:none;margin-right:10px;">Facebook</a> <a href="https://instagram.com/totalguardyardcare" style="color:#C5A55A;font-size:12px;text-decoration:none;margin-right:10px;">Instagram</a> <a href="https://g.page/r/CRW5Dsg2JgwBEBM/review" style="color:#C5A55A;font-size:12px;text-decoration:none;">Google</a></td></tr><tr><td style="color:#666;font-size:10px;padding-top:10px;">Serving Madison, Middleton, Waunakee, Monona, Sun Prairie, Fitchburg, Verona, McFarland, Cottage Grove, DeForest, Oregon & Stoughton</td></tr></table></td></tr></table></td></tr></table></body></html>`;
}

const serviceDescriptions = {
  'Lawn Mowing': 'Keep your lawn perfectly manicured with our weekly mowing service — consistent height, clean edges, and clippings managed.',
  'Fertilization': 'Our custom fertilization program feeds your lawn the nutrients it needs for thick, green growth all season.',
  'Aeration': 'Core aeration breaks up compacted soil, allowing water, air, and nutrients to reach grass roots for a healthier lawn.',
  'Weeding': 'Targeted weed control that eliminates dandelions, crabgrass, and broadleaf weeds without harming your lawn.',
  'Spring Cleanup': 'Complete spring revival: debris removal, bed edging, first mow, and prep to get your yard season-ready.',
  'Fall Cleanup': 'Thorough fall service: leaf removal, bed cleanup, final mow, and winterization to protect your lawn.',
  'Mulching': 'Fresh mulch transforms garden beds — suppresses weeds, retains moisture, and gives your landscape a polished look.',
  'Garden Bed Care': 'Professional bed maintenance: weeding, edging, planting, and seasonal color for beautiful curb appeal.',
  'Bush Trimming': 'Expert shrub and hedge trimming that maintains natural shape while promoting healthy, dense growth.',
  'Gutter Cleaning': 'Complete gutter and downspout cleaning to prevent water damage, ice dams, and foundation issues.',
  'Gutter Guard Installation': 'Premium gutter guards that keep debris out permanently — no more climbing ladders to clean gutters.',
  'Leaf Removal': 'Thorough leaf removal from lawn, beds, and hard surfaces so your property stays clean and your lawn can breathe.',
  'Hardscaping': 'Custom patios, walkways, retaining walls, and fire pits that add beauty and value to your outdoor living space.',
  'Herbicide Services': 'Targeted herbicide application that eliminates weeds at the root while keeping your lawn and garden safe.',
  'Snow Removal': 'Reliable snow removal triggered at 2"+ snowfall — driveway, walks, porch, and salt application.'
};

const map = { 'Lawn Mowing': ['Fertilization','Aeration','Weeding'], 'Spring Cleanup': ['Lawn Mowing','Mulching','Garden Bed Care'], 'Fall Cleanup': ['Leaf Removal','Gutter Cleaning','Aeration'], 'Gutter Cleaning': ['Gutter Guard Installation','Fall Cleanup'], 'Snow Removal': ['Spring Cleanup'], 'Garden Bed Care': ['Mulching','Bush Trimming','Hardscaping'], 'Fertilization': ['Aeration','Herbicide Services'], 'Leaf Removal': ['Gutter Cleaning','Fall Cleanup'], 'Aeration': ['Fertilization','Herbicide Services'], 'Mulching': ['Garden Bed Care','Bush Trimming'] };

// Build dedup set from sent history
const sentItems = $('Fetch Sent History').all().map(i => i.json);
const sentSet = new Set(sentItems.map(s => `${s.contact_email}|${s.email_type}`));

const results = [];
for (const item of $input.all()) {
  const job = item.json;
  const suggestions = map[job.parsed_service] || ['Lawn Mowing','Spring Cleanup'];
  const suggest = suggestions[0];
  const dedupKey = `${job.parsed_customer_email}|cross_sell_${suggest}`;
  if (sentSet.has(dedupKey)) continue;

  const name = job.parsed_customer_name || 'there';
  const completedService = job.parsed_service || 'yard care';
  const suggestDesc = serviceDescriptions[suggest] || `Professional ${suggest.toLowerCase()} service for your Madison property.`;
  const subject = `Have you tried TotalGuard's ${suggest}?`;
  const body = `Hi ${name},\n\nGlad your ${completedService} went well! Many of our Madison customers also love our ${suggest} service.\n\nInterested? Book at tgyardcare.com or call (608) 535-6057.\n\n- TotalGuard Team`;

  const htmlBody = buildEmailHtml({
    subject,
    headline: `Loved your ${completedService}? You'll love ${suggest} too!`,
    bodyHtml: `<p>Hi ${name},</p><p>We're glad your recent <strong>${completedService}</strong> service went well! Based on your property, we think you'd also benefit from our <strong>${suggest}</strong> service.</p><p style="background:#f5f5f0;padding:16px;border-radius:6px;"><strong>${suggest}:</strong> ${suggestDesc}</p><p>Many of our Madison customers bundle these services together for a complete yard care solution — and save time coordinating everything with one trusted team.</p>`,
    reviewText: 'Started with just mowing and now TotalGuard handles everything — fertilization, cleanups, even our gutters. So much easier having one team that knows our property.',
    reviewerName: 'Jennifer T., Fitchburg',
    ctaText: `Add ${suggest} to My Services`,
    ctaUrl: 'https://tgyardcare.com',
    urgencyText: 'Bundle multiple services and simplify your yard care — one team, one schedule, one trusted partner.',
    previewText: `Your ${completedService} went great! Here's a service we think you'll love.`
  });

  results.push({ json: { ...job, suggest_service: suggest, subject, body, htmlBody } });
}
return results.length > 0 ? results : [{ json: { _skip: true } }];
